{
 "level": "A2–B1",
 "intro": "In this topic you will learn the <strong>position of adverbs</strong> in English sentences: adverbs of frequency, mode of action, place, time and degree.",
 "rules": [
 {
 "label": "Frequency",
 "color": "emerald",
 "text": "<strong>Always, often, never</strong> — before the main verb, after to be:",
 "example": "She always eats breakfast."
 },
 {
 "label": "Manner",
 "color": "blue",
 "text": "<strong>Quickly, well, carefully</strong> — at the end of the sentence:",
 "example": "He speaks English fluently."
 },
 {
 "label": "Place + Time",
 "color": "amber",
 "text": "<strong>Order:</strong> Manner → Place → Time:",
 "example": "She worked hard in London last year."
 }
 ]
}

{
 "title": "1. Three positions of adverbs",
 "intro": "Adverbs can occupy three main positions in a sentence:",
 "items": [
 {
 "label": "Front",
 "title": "At the beginning",
 "subtitle": "Before the subject: Yesterday, I met my friend."
 },
 {
 "label": "Mid",
 "title": "In the middle",
 "subtitle": "Between the subject and the verb: She always drinks coffee."
 },
 {
 "label": "End",
 "title": "At the end",
 "subtitle": "After the verb/adverb: He speaks English fluently."
 }
 ]
}

{
 "title": "2. Adverbs of Frequency",
 "sections": [
 {
 "label": "Before the main verb",
 "color": "emerald",
 "description": "The adverbs <strong>always, usually, often, sometimes, rarely, never</strong> are placed <strong>before</strong> the main verb.",
 "examples": [
 {
 "en": "She always eats breakfast.",
 "ua": "She always eats breakfast."
 },
 {
 "en": "I often go to the gym.",
 "ua": "I often go to the gym."
 },
 {
 "en": "They never drink coffee.",
 "ua": "They never drink coffee."
 }
 ]
 },
 {
 "label": "After the verb TO BE",
 "color": "sky",
 "description": "If the verb <strong>to be</strong>, the adverb of frequency is placed <strong>after</strong> him.",
 "examples": [
 {
 "en": "He is always late.",
 "ua": "He is always late."
 },
 {
 "en": "She is usually happy.",
 "ua": "She is usually happy."
 },
 {
 "en": "They are rarely bored.",
 "ua": "They are rarely bored."
 }
 ]
 },
 {
 "label": "After the auxiliary verb",
 "color": "amber",
 "description": "In compound tenses, the adverb comes <strong>after</strong> the auxiliary verb.",
 "examples": [
 {
 "en": "I have never been to Paris.",
 "ua": "I have never been to Paris."
 },
 {
 "en": "She has always wanted a dog.",
 "ua": "She has always wanted a dog."
 },
 {
 "en": "They will usually arrive on time.",
 "ua": "They will usually arrive on time."
 }
 ],
 "note": "<strong>Sometimes, usually, often</strong> can stand at the beginning accent."
 }
 ]
}

{
 "title": "3. Adverbs of Manner",
 "sections": [
 {
 "label": "At the end of a sentence",
 "color": "emerald",
 "description": "Adverbs <strong>quickly, slowly, carefully, well, badly, beautifully</strong> usually stand <strong>at the end</strong> of a sentence.",
 "examples": [
 {
 "en": "She sings beautifully.",
 "ua": "She sings beautifully."
 },
 {
 "en": "He finished the test quickly.",
 "ua": "He finished the test quickly."
 },
 {
 "en": "They work hard every day.",
 "ua": "They work hard every day."
 }
 ]
 },
 {
 "label": "After an adverb",
 "color": "sky",
 "description": "If there is an adverb, the adverb of action is <strong>after</strong> it.",
 "examples": [
 {
 "en": "She speaks English fluently.",
 "ua": "She speaks English fluently."
 },
 {
 "en": "He plays the piano well.",
 "ua": "He plays the piano well."
 },
 {
 "en": "They did the work carefully.",
 "ua": "They did the work carefully."
 }
 ],
 "note": "❌ <em>She speaks fluent English</em> is wrong!"
 }
 ]
}

{
 "title": "4. Adverbs of Place (Adverbs of Place) here.",
 "sections": [
 {
 "label": "At the end of the sentence",
 "color": "emerald",
 "description": "Place adverbials like <strong>here, there, at home, in the park, at school</strong> usually go <strong>at the end</strong>.",
 "examples": [
 {
 "en": "She lives here.",
 "ua": "She lives here."
 },
 {
 "en": "He works at the office.",
 "ua": "He works at the office."
 },
 {
 "en": "The children play in the park.",
 "ua": "The children play in the park."
 }
 ]
 },
 {
 "label": "At the beginning for emphasis",
 "color": "sky",
 "description": "In formal style or for emphasis, the adverbial of place can be at the beginning.",
 "examples": [
 {
 "en": "Here is your book.",
 "ua": "Here is your book."
 },
 {
 "en": "There goes the bus.",
 "ua": "There goes the bus."
 }
 ]
 }
 ]
}

{
 "title": "5. Adverbs of Time",
 "sections": [
 {
 "label": "At the end of a sentence",
 "color": "emerald",
 "description": "Adverbs of Time (<strong>yesterday, today, tomorrow, last week, every day</strong>) are usually <strong>at the end</strong>.",
 "examples": [
 {
 "en": "I wake up at 6 o'clock.",
 "ua": "I wake up at 6 o'clock."
 },
 {
 "en": "She studies English every day.",
 "ua": "She studies English every day."
 },
 {
 "en": "We went to the cinema last night. We went to the cinema last night. friend.",
 "ua": "We went to the cinema last night. We went to the cinema last night. friend."
 }
 ]
 },
 {
 "label": "At the beginning for emphasis",
 "color": "sky",
 "description": "For emphasis, time adverbials can go <strong>at the beginning</strong>.",
 "examples": [
 {
 "en": "Yesterday, I met an old friend.",
 "ua": "Yesterday, I met an old friend."
 },
 {
 "en": "Every morning, she jogs in the park.",
 "ua": "Every morning, she jogs in the park."
 }
 ]
 },
 {
 "label": "Several time adverbials",
 "color": "amber",
 "description": "If there are several time adverbials, the more specific one usually comes first.",
 "examples": {
 "en": "He is leaving at 10 a.m. on Monday.",
 "ua": "He is leaving at 10 a.m. on Monday."
 }
 }
 ]
}

{
 "title": "6. Order of adverbials (Manner → Place → Time)",
 "intro": "If there are several adverbials at the end of the sentence, the order is as follows:",
 "rows": [
 {
 "en": "Manner",
 "ua": "Manner",
 "note": "hard, quickly, well"
 },
 {
 "en": "Place",
 "ua": "Place",
 "note": "in London, at home, here"
 },
 {
 "en": "Time",
 "ua": "Time",
 "note": "yesterday, last year, every day"
 }
 ],
 "warning": "📌 Example: <strong>She worked hard in London last year.</strong>"
}

{
 "title": "7. Adverbs of Degree",
 "sections": [
 {
 "label": "Before an adjective/adverb",
 "color": "emerald",
 "description": "The adverbs <strong>very, quite, really, extremely, fairly</strong> stand <strong>before</strong> the word they modify.",
 "examples": [
 {
 "en": "She is very smart.",
 "ua": "She is very smart."
 },
 {
 "en": "He runs quite fast.",
 "ua": "He runs quite fast."
 },
 {
 "en": "The movie was extremely boring.",
 "ua": "The movie was extremely boring."
 }
 ]
 },
 {
 "label": "A lot, much",
 "color": "sky",
 "description": "Adverbs such as <strong>a lot</strong> and <strong>much</strong> usually go at the end.",
 "examples": [
 {
 "en": "We travel a lot.",
 "ua": "We travel a lot."
 },
 {
 "en": "I like it very much.",
 "ua": "I like it very much."
 }
 ]
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Manner before the objectlication instead of after.",
 "wrong": "She speaks fluent English.",
 "right": "​​​​ <span class=\"font-mono\">She speaks English fluently.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Frequency at the beginning instead of before the verb.",
 "wrong": "Always I drink coffee.",
 "right": "​​​​​​​​​​​​ before."
 },
 {
 "label": "Mistake 3",
 "color": "sky",
 "title": "Putting frequency after the verb instead of before it.",
 "wrong": "He goes often to the gym.",
 "right": " ✅ <span class=\"font-mono\">He often goes to the gym.</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Time in the middle of the sentence.",
 "wrong": "I saw yesterday him.",
 "right": " ✅ <span class=\"font-mono\">I saw him yesterday.</span>"
 }
 ]
}

{
 "title": "10. Practice",
 "select_title": "Exercise 1. Choose the correct option",
 "select_intro": "Choose the sentence with the correct placement of the adverb.",
 "selects": [
 {
 "label": "a) She always drinks coffee. / b) She always drinks coffee.",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) He speaks fluent English. / b) He speaks English fluently.",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) I yesterday saw him. / b) I saw him yesterday.",
 "prompt": "Which option is correct?"
 }
 ],
 "options": [
 "a",
 "b"
 ],
 "input_title": "Exercise 2. Put the adverb in the right place",
 "input_intro": "Put the adverb in the right place.",
 "inputs": [
 {
 "before": "She is late. (always)",
 "after": "→"
 },
 {
 "before": "He plays the piano. (well)",
 "after": "→"
 },
 {
 "before": "They work. / in the office / everyday happy.",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Fix the mistakes",
 "rephrase_intro": "Find and fix the adverb-position mistake.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "Always he is happy.",
 "example_target": "He is always happy."
 },
 {
 "original": "1. She speaks well French.",
 "placeholder": "Correct word order"
 },
 {
 "original": "2. never I have been to Japan. and adverbials",
 "placeholder": "Fix the word order"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Basic Word Order",
 "current": false
 },
 {
 "label": "Word Order in Questions and Negatives",
 "current": false
 },
 {
 "label": "Word Order with Adverbs",
 "current": true
 }
 ]
}
